-- ============================================================================
-- LPDP Prep — TBS questions table + seed
-- Run AFTER schema.sql.
-- ============================================================================

create table if not exists public.tbs_questions (
  id uuid default gen_random_uuid() primary key,
  category text not null check (category in ('verbal', 'numerik', 'logika')),
  subcategory text,
  question text not null,
  options jsonb not null,
  answer_index int not null check (answer_index >= 0),
  explanation text,
  difficulty text default 'medium',
  user_id uuid references auth.users on delete set null,
  created_at timestamptz default now()
);

create index if not exists tbs_questions_cat_idx on public.tbs_questions(category);
create index if not exists tbs_questions_sub_idx on public.tbs_questions(subcategory);

-- RLS: public read so tests work without login. Auth users can manage their own contributions.
alter table public.tbs_questions enable row level security;

drop policy if exists "tbs_q_public_read" on public.tbs_questions;
drop policy if exists "tbs_q_insert_auth" on public.tbs_questions;
drop policy if exists "tbs_q_update_own" on public.tbs_questions;
drop policy if exists "tbs_q_delete_own" on public.tbs_questions;

create policy "tbs_q_public_read" on public.tbs_questions
  for select using (true);
create policy "tbs_q_insert_auth" on public.tbs_questions
  for insert with check (auth.uid() = user_id);
create policy "tbs_q_update_own" on public.tbs_questions
  for update using (auth.uid() = user_id);
create policy "tbs_q_delete_own" on public.tbs_questions
  for delete using (auth.uid() = user_id);

-- ============================================================================
-- Seed: 188 questions from PDF "Kumpulan Soal Latihan TBS LPDP"
-- Run only once. Re-running will create duplicates (questions table has no
-- natural unique key — clear table first if re-seeding).
-- ============================================================================

